/*===================================================================================================================================*/
/*  U1      u1_g_oXDoCANRebyId_A001(U1 * u1_ap_ans, const U2 u2_a_ELPSD)                                                             */
/* --------------------------------------------------------------------------------------------------------------------------------- */
/*  Arguments:                                                                                                                       */
/*  Return:                                                                                                                          */
/*===================================================================================================================================*/
U1      u1_g_oXDoCANRebyId_A001(U1 * u1_ap_ans, const U2 u2_a_ELPSD)
{
    u1_ap_ans[0] = (U1)OXDC_DIDA001_DATA0;
    u1_ap_ans[1] = (U1)OXDC_DIDA001_DATA1;
    u1_ap_ans[2] = (U1)OXDC_DIDA001_DATA2;
    return((U1)OXDC_SAL_PROC_FIN);
}
/*===================================================================================================================================*/
/*  U1      u1_g_oXDoCANRebyId_A100(U1 * u1_ap_ans, const U2 u2_a_ELPSD)                                                             */
/* --------------------------------------------------------------------------------------------------------------------------------- */
/*  Arguments:                                                                                                                       */
/*  Return:                                                                                                                          */
/*===================================================================================================================================*/
U1      u1_g_oXDoCANRebyId_A100(U1 * u1_ap_ans, const U2 u2_a_ELPSD)
{
    if(u2_a_ELPSD == (U2)0U){
        vd_g_oXDoCANXidSupInit((U2)0U, u1_ap_ans);
    }
    return(u1_g_oXDoCANXgrSupchk(&st_gp_OXDC_DATA_XID[0], u2_g_OXDC_DATA_NUM_XID, u1_ap_ans));
}
/*===================================================================================================================================*/
/*  U1      u1_g_oXDoCANRebyId_A1XX(U1 * u1_ap_ans, const U2 u2_a_ELPSD)                                                             */
/* --------------------------------------------------------------------------------------------------------------------------------- */
/*  Arguments:                                                                                                                       */
/*  Return:                                                                                                                          */
/*===================================================================================================================================*/
U1      u1_g_oXDoCANRebyId_A1XX(U1 * u1_ap_ans, const U2 u2_a_ELPSD)
{
    if(u2_a_ELPSD == (U2)0U){
        vd_g_oXDoCANDidSupInit(u2_gp_oxdc_rebyid_xidlist[u1_g_oxdc_rebyid_xidcnt], u1_ap_ans);
    }
    return(u1_g_oXDoCANXidSupchk(&st_gp_OXDC_DATA_XID[0], u2_g_OXDC_DATA_NUM_XID, u1_ap_ans));
}
